                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        app.get('/api/tasks/:userId', (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const user = usersDatabase[req.params.userId];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                if (!user) return res.status(404).json({ message: "User registry entry missing." });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const taskStatus = AVAILABLE_TASKS.map(task => ({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            ...task,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    completed: user.completedTasks.includes(task.id)
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }));

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            res.json({ 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    totalPoints: user.points, 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            energy: user.energy, 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    tasks: taskStatus 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        app.post('/api/tasks/claim', (req, res) => {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const { userId, taskId } = req.body;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const user = usersDatabase[userId];
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const task = AVAILABLE_TASKS.find(t => t.id === taskId);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (!user || !task) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                return res.status(400).json({ message: "Invalid claim attempt parameters request." });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if (user.completedTasks.includes(taskId)) {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    console.warn(`[REWARD WARNING] User ${user.username} attempted to double claim task: ${taskId}`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            return res.status(400).json({ message: "Security Warning: Task reward already claimed." });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    user.points += task.reward;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        user.completedTasks.push(taskId);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                console.log(`[REWARD SUCCESS] User ${user.username} successfully claimed +${task.reward} BP for ${taskId}`);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    res.json({ message: `Successfully claimed ${task.reward} points!`, totalPoints: user.points });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });

